// $http polyfill — not available in Code node sandbox (N8N_RUNNERS_ENABLED=false)
function nocoReq(method, urlStr, tkn, payload) {
  return new Promise((resolve, reject) => {
    const lib = urlStr.startsWith('https') ? require('https') : require('http');
    const hdrs = { 'xc-token': tkn, 'Accept': 'application/json' };
    let bodyStr = null;
    if (payload) {
      bodyStr = JSON.stringify(payload);
      hdrs['Content-Type'] = 'application/json';
      hdrs['Content-Length'] = Buffer.byteLength(bodyStr);
    }
    const req = lib.request(urlStr, { method, headers: hdrs }, (res) => {
      let d = ''; res.on('data', c => d += c);
      res.on('end', () => {
        if (res.statusCode >= 400) { reject(new Error('HTTP ' + res.statusCode + ': ' + d.slice(0,200))); return; }
        try { resolve(JSON.parse(d)); } catch(e) { resolve(d); }
      });
    });
    req.on('error', reject);
    if (bodyStr) req.write(bodyStr);
    req.end();
  });
}

const data = $input.first().json;
const body = data.body || data;

const expectedSecret = $env.N8N_WEBHOOK_HMAC_SECRET;
if (!expectedSecret) throw new Error('N8N_WEBHOOK_HMAC_SECRET not configured');
const receivedSecret = (data.headers || {})['x-webhook-secret'] || body.secret || '';
if (receivedSecret !== expectedSecret) throw new Error('Unauthorized: invalid webhook secret');

const content_id = body.content_id;
if (!content_id) throw new Error('Missing required field: content_id');

const fields = body.fields || {};
if (Object.keys(fields).length === 0) throw new Error('Missing required field: fields (nothing to update)');

const patchFields = {};
for (const [key, value] of Object.entries(fields)) {
  patchFields[key] = (typeof value === 'object' && value !== null) ? JSON.stringify(value) : value;
}

const baseUrl = $env.NOCODB_BASE_URL;
const token = $env.NOCODB_API_TOKEN;
const contentsId = $env.NOCODB_CONTENTS_TABLE_ID || '';
if (!contentsId) throw new Error('NOCODB_CONTENTS_TABLE_ID not configured');

await nocoReq('PATCH', baseUrl + '/api/v2/tables/' + contentsId + '/records', token, { Id: parseInt(content_id), ...patchFields });

return [{ json: { status: 'ok', content_id: String(content_id) } }];
